<?php

declare(strict_types=1);
require_once __DIR__ . '/support.php';
$boot=require dirname(__DIR__).'/app/bootstrap.php';$root=$boot['root'];$iterations=max(100,(int)($argv[1]??5000));$failureRate=min(0.8,max(0.0,(float)($argv[2]??0.10)));$tmp=$root.'/runtime/load-fault-'.bin2hex(random_bytes(4));mkdir($tmp,0700,true);
